async def seed(session: AsyncSession) -> None:
    stmt = pg_insert(CaseScenario).values(
        [
            {
                "id": c["id"],
                "title": c["title"],
                "description": c["description"],
                "difficulty": c["difficulty"],
                "category": c["category"],
                "estimated_minutes": c["estimated_minutes"],
                "max_score": c["max_score"],
                "optimal_path": c["optimal_path"],
                "expert_analysis": c["expert_analysis"],
                "steps": c["steps"],
                "order_index": c["order_index"],
                "is_active": True,
            }
            for c in CASES
        ]
    )
    stmt = stmt.on_conflict_do_update(
        index_elements=["id"],
        set_={
            "title": stmt.excluded.title,
            "description": stmt.excluded.description,
            "difficulty": stmt.excluded.difficulty,
            "category": stmt.excluded.category,
            "estimated_minutes": stmt.excluded.estimated_minutes,
            "max_score": stmt.excluded.max_score,
            "optimal_path": stmt.excluded.optimal_path,
            "expert_analysis": stmt.excluded.expert_analysis,
            "steps": stmt.excluded.steps,
            "order_index": stmt.excluded.order_index,
            "is_active": stmt.excluded.is_active,
        },
    )
    await session.execute(stmt)
    await session.commit()
    logger.info("Seeded %d case scenarios", len(CASES))


async def main() -> None:
    logging.basicConfig(level=logging.INFO)
    async with async_session() as session:
        await seed(session)


if __name__ == "__main__":
    asyncio.run(main())
